#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=1000005;
string s;
int x[N],y[N],cnt[N],sa[N],rk[N],height[N];
int n,m;
void SA()
{
	for(int i=1;i<=n;i++)
	{
		cnt[x[i]=s[i]]++;
	}
	for(int i=2;i<=m;i++)
	{
		cnt[i]+=cnt[i-1];
	}
	for(int i=n;i>=1;i--)
	{
		sa[cnt[x[i]]--]=i;
	}
	for(int k=1;k<=n;k*=2)
	{
		int num=0;
		for(int i=n-k+1;i<=n;i++) y[++num]=i;
		for(int i=1;i<=n;i++)
		{
			if(sa[i]>k) y[++num]=sa[i]-k;
		}
		for(int i=1;i<=m;i++)
		{
			cnt[i]=0;
		}
		for(int i=1;i<=n;i++)
		{
			cnt[x[i]]++;
		}
		for(int i=2;i<=m;i++)
		{
			cnt[i]+=cnt[i-1];
		}
		for(int i=n;i>=1;i--)
		{
			sa[cnt[x[y[i]]]--]=y[i];
			y[i]=0;
		}
		swap(x,y);
		x[sa[1]]=1;
		num=1;
		for(int i=2;i<=n;i++)
		{
			x[sa[i]]=((y[sa[i]]==y[sa[i-1]])&&(y[sa[i]+k]==y[sa[i-1]+k]))?num:++num;
			//如果这两个后缀判断到目前都一样 但存在数组里位置肯定不同 那它们在下一轮应该有相同的排名 
		}
		if(num==n) break;
		m=num;
	}
	for(int i=1;i<=n;i++) cout<<sa[i]<<" ";
}
void get_height()//这道题没用到这个 
{
	int k=0;
	for(int i=1;i<=n;++i) rk[sa[i]]=i;
	for(int i=1;i<=n;++i)  
	{
		if(rk[i]==1) continue;//第一名height为0
		if(k) k--;//h[i]>=h[i-1]+1;
		int j=sa[rk[i]-1];
		while((j+k<=n)&&(i+k<=n)&&(s[i+k]==s[j+k])) k++;
		height[rk[i]]=k;//h[i]=height[rk[i]];
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>s;
	s=" "+s;
	n=s.size()-1;
	m=122;//m为字符个数 ascll('z')=122
	SA();
	return 0;
}
